1	const countLiveNeighbors = (x: number, y: number, alive: Set<string>): number => {
2	  let count = 0;
3	  for (let dx = -1; dx <= 1; dx++) {
4	    for (let dy = -1; dy <= 1; dy++) {
5	      if (dx === 0 && dy === 0) continue;
6	      if (alive.has(`${x + dx},${y + dy}`)) count++;
7	    }
8	  }
9	  return count;
10	};
