12	export const nextGeneration = (liveCells: number[][]): number[][] => {
13	  const alive = new Set(liveCells.map(([x, y]) => `${x},${y}`));
14	
15	  return liveCells.filter(([x, y]) => {
16	    const neighbors = countLiveNeighbors(x, y, alive);
17	    return neighbors >= 2 && neighbors <= 3;
18	  });
19	};
